{
  "reconstructed_intent": "用户希望了解其购买的重疾险在发生合同定义的轻症时，是否可以获得多次赔付以及每次赔付的具体金额。用户可能对保险条款不熟悉，因此期望得到一个通俗易懂且涵盖关键规则的回答。",
  "judge_basis": "以提供的参考答案作为正确性和完整性的基准，结合用户问题的具体意图，评估候选答案的准确性、完整性和有用性。重点检查候选答案是否回答了核心问题，是否遗漏影响用户理解的重要信息，以及是否存在错误或矛盾。",
  "judge_method": "首先解析用户问题，提取关键疑问点（是否多次赔付、每次赔多少）。然后对照参考答案，验证候选答案的事实准确性。识别候选答案中包含的关键信息点，判断是否覆盖了回答用户问题所需的核心要素。评估候选答案在清晰度、实用性和安全建议方面的表现。",
  "reasoning_summary": "候选答案准确回答了用户关于轻症多次赔付和赔付金额的核心问题，明确说明轻症可以多次赔付，并给出了每次赔付金额为基本保额20%至30%的常见比例。同时提示了次数上限和间隔期等限制条件，并建议用户查阅具体合同。所有信息与参考答案关键事实一致，无矛盾或错误，完全满足用户的直接询问需求。",
  "scenario": "qa_gold_answer",
  "business_expectations": [
    {
      "expectation_id": "回答轻症是否可多次赔付",
      "description": "答案应明确说明轻症一般情况下可以多次赔付。",
      "acceptance_criteria": "答案中包含肯定的表述，如“轻症可以赔付多次”。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "提供每次赔付金额的一般比例",
      "description": "答案应提供每次轻症赔付金额相对于基本保额的常见比例范围。",
      "acceptance_criteria": "答案中明确提到了20%-30%或其他合理比例。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "提及次数上限和间隔期等限制",
      "description": "答案应提醒用户轻症多次赔付可能存在次数上限和两次赔付之间的间隔期要求。",
      "acceptance_criteria": "答案中提到了次数上限（如3次或5次）和间隔期。",
      "blocking_level": "blocking"
    },
    {
      "expectation_id": "建议查阅具体合同",
      "description": "答案应建议用户以保险合同为准，或咨询保险公司客服获取准确信息。",
      "acceptance_criteria": "答案包含类似建议，如“建议查阅您的保险合同条款”。",
      "blocking_level": "non-blocking"
    },
    {
      "expectation_id": "无矛盾或错误信息",
      "description": "答案中的事实性描述应与一般保险规则及参考答案一致，不得包含误导性错误。",
      "acceptance_criteria": "答案中所有信息均无矛盾或错误。",
      "blocking_level": "blocking"
    }
  ],
  "fulfillment_assessments": [
    {
      "expectation_id": "回答轻症是否可多次赔付",
      "status": "fulfilled",
      "reason": "候选答案明确说明'轻症可以赔付多次'，直接回答了该问题。"
    },
    {
      "expectation_id": "提供每次赔付金额的一般比例",
      "status": "fulfilled",
      "reason": "候选答案提到'每次赔付金额通常为基本保险金额的20%至30%'，符合常见比例。"
    },
    {
      "expectation_id": "提及次数上限和间隔期等限制",
      "status": "fulfilled",
      "reason": "候选答案提到'可能有次数上限（如3次或5次）和间隔期要求'，涵盖了这些限制条件。"
    },
    {
      "expectation_id": "建议查阅具体合同",
      "status": "fulfilled",
      "reason": "候选答案以'建议查阅您的保险合同条款获取准确信息'结尾，提供了必要建议。"
    },
    {
      "expectation_id": "无矛盾或错误信息",
      "status": "fulfilled",
      "reason": "候选答案中的所有信息与参考答案及一般保险规则一致，未发现矛盾或错误。"
    }
  ],
  "overall_fulfillment": {
    "status": "fulfilled"
  },
  "quality_flags": []
}

